// src/pages/Admin/AllBookings.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";

const AllBookings = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    const fetchBookings = async () => {
      try {
        const res = await axios.get("http://localhost:5000/api/bookings/all/bookings", {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        setBookings(res.data.bookings);
        setLoading(false);
      } catch (err) {
        console.error(err);
        setLoading(false);
      }
    };

    fetchBookings();
  }, [user.token]);

  if (loading) return <p className="loading-text">Loading all bookings...</p>;

  return (
    <div className="container">
      <h2>All Bookings</h2>
      {bookings.length === 0 ? (
        <p>No bookings found.</p>
      ) : (
        <table>
          <thead>
            <tr>
              <th>User</th>
              <th>Event</th>
              <th>Tickets</th>
              <th>Total</th>
              <th>Status</th>
              <th>Payment</th>
            </tr>
          </thead>
          <tbody>
            {bookings.map((b) => (
              <tr key={b._id}>
                <td>{b.user.name}</td>
                <td>{b.event.name}</td>
                <td>{b.numberOfTickets}</td>
                <td>${b.totalAmount}</td>
                <td>{b.status}</td>
                <td>{b.paymentStatus}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default AllBookings;
